def pacific_atlantic(heights):
 m,n=len(heights),len(heights[0])
 p=[[False]*n for _ in range(m)]
 a=[[False]*n for _ in range(m)]
 def dfs(i,j,ocean):
  ocean[i][j]=True
  for di,dj in[(1,0),(-1,0),(0,1),(0,-1)]:
   ni,nj=i+di,j+dj
   if 0<=ni<m and 0<=nj<n and not ocean[ni][nj]and heights[ni][nj]>=heights[i][j]:
    dfs(ni,nj,ocean)
 for i in range(m):dfs(i,0,p);dfs(i,n-1,a)
 for j in range(n):dfs(0,j,p);dfs(m-1,j,a)
