def partition(s):
 n=len(s);isp=[[False]*n for _ in range(n)]
 for i in range(n-1,-1,-1):
  for j in range(i,n):
   isp[i][j]=s[i]==s[j]and(j-i<2 or isp[i+1][j-1])
