class MyQueue:
 def __init__(self):self.in_=[];self.out=[]
 def push(self,x):self.in_.append(x)
 def pop(self):
  if not self.out:
   while self.in_:self.out.append(self.in_.pop())
  return self.out.pop()
 def peek(self):
  if not self.out:
   while self.in_:self.out.append(self.in_.pop())
  return self.out[-1]
 def empty(self):return not self.in_ and not self.out
```
