 def _hash(self,key):return key%769
 def put(self,key,value):
  idx=self._hash(key)
  for i,(k,v)in enumerate(self.buckets[idx]):
   if k==key:self.buckets[idx][i]=(k,value);return
  self.buckets[idx].append((key,value))
 def get(self,key):
  for k,v in self.buckets[self._hash(key)]:
   if k==key:return v
  return-1
